defmodule WebhookController do
  use Phoenix.Controller

  alias Httpotion.Response
  import Httpotion.Client

  plug :accepts, ["json"]

  def index(conn, _params) do
    params = conn.params
    url = params["url"]

    case get(url) do
      {:ok, response} ->
        send_resp(conn, 200, response.body)
      {:error, %Httpotion.Error{reason: reason}} ->
        send_resp(conn, 500, "Failed to fetch data from #{url}: #{inspect(reason)}")
    end
  end

  defp get(url) do
    with{:ok, client} <- Httpotion.start(),
         :ok <- request(client, url),
         {:ok, %Response{status_code: 200..399}} = inspect_response() do
      {:ok, response}
    else
      {:error, reason}
    end

    defp request(client, url) do
      send_request(client, :get, url) |> Map.put-kw(:headers, [("Accept", "application/json")])
    end

    defp inspect_response() do
      case response = receive_response() do
        {:ok, response} ->
          {:ok, response}
        {:error, reason} ->
          {:error, %Httpotion.Error{reason: reason}}
      end

      defp receive_response() when is_binary(response) do
        {:ok, Poison.decode!(JSON.parse!(response))}
      end

      defp receive_response() do
        {:error, "Unexpected response type"}
      end
    end
  end
end